  ('locality-e3452428-moex-00187', 'locality-e3452428', 'locality-e3452428-moex-112-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於即時強制之損失補償，下列敘述何者正確？', '["損失補償，應以回復原狀為原則，例外以金錢為之", "損失補償不以補償實際所受之特別損失為限", "因可歸責於該人民之事由，執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失 時，得請求補償", "損失補償，應於知有損失後，2年內向執行機關請求之。但自損失發生後，經過5年者，不得為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "302", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00188', 'locality-e3452428', 'locality-e3452428-moex-112-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政程序法聽證，下列敘述何者正確？', '["須有法律規定作為舉行聽證之依據", "得為預備聽證，必要時亦得再為聽證", "經聽證程序作成之行政處分，無後續救濟管道", "聽證以不公開為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "302", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00189', 'locality-e3452428', 'locality-e3452428-moex-112-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依實務見解，人民甲依訴願法第2條規定提起訴願，受理訴願機關尚未作成決定前，應作為之乙 機關已作成行政處分，而甲仍對於乙機關所作成之處分向訴願機關表示不服，此時受理訴願機關 應如何處理？', '["訴願機關應續行訴願程序，對嗣後所為之行政處分進行審查", "不論該處分有利或不利於訴願人，皆應依訴願法第82條第2項規定駁回訴願", "因乙機關已作成行政處分，甲之訴願無理由，應駁回其訴願", "因乙機關已作成行政處分，甲已無權利保護必要，應駁回其訴願"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "302", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
