  ('locality-e3452428-moex-00191', 'locality-e3452428', 'locality-e3452428-moex-112-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '下列何者非屬一般給付訴訟所得請求之內容？', '["稅捐稽徵機關辦理退稅，誤將退稅款匯入他人帳戶，向該他人請求返還", "行政契約之相對人因故不履行契約，行政機關請求其履行", "人民請求主管機關勿作成裁處沒入之處分", "人民請求主管機關作成營業補貼處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "302", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00192', 'locality-e3452428', 'locality-e3452428-moex-112-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '有關行政訴訟審判權之敘述，下列何者正確？', '["依道路交通管理處罰條例裁處罰鍰事件，歸屬地方法院刑事庭管轄", "地方議會侵害議員之質詢權，由行政法院審理", "受懲戒之律師對於律師懲戒委員會之決議不服者，由行政法院審理", "違法羈押事件，由行政法院審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "302", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
